import { Component, OnInit, computed, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Router } from '@angular/router';
import { HttpClient } from '@angular/common/http';
import { environment } from '../../../environments/environment';
import { Profile, SwipeDirection } from '../../core/models';
import { ToastService } from '../../core/services/toast.service';

interface SwipeResponse {
  match?: boolean;
}

@Component({
  selector: 'app-feed',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './feed.component.html',
  styleUrl: './feed.component.css',
})
export class FeedComponent implements OnInit {
  private router = inject(Router);
  private toast = inject(ToastService);
  private http = inject(HttpClient);
  private readonly apiUrl = environment.apiUrl;

  readonly profiles = signal<Profile[]>([]);

  readonly index = signal(0);
  readonly lastDirection = signal<SwipeDirection | null>(null);

  readonly current = computed<Profile | null>(() => this.profiles()[this.index()] ?? null);
  readonly next = computed<Profile | null>(() => this.profiles()[this.index() + 1] ?? null);
  readonly exhausted = computed(() => this.index() >= this.profiles().length);
  readonly remaining = computed(() => Math.max(0, this.profiles().length - this.index()));

  ngOnInit(): void {
    this.load();
  }

  private load(): void {
    this.http.get<Profile[]>(`${this.apiUrl}/feed`).subscribe({
      next: (profiles) => {
        this.profiles.set(profiles ?? []);
        this.index.set(0);
      },
      error: () => this.profiles.set([]),
    });
  }

  swipe(direction: SwipeDirection): void {
    const profile = this.current();
    if (!profile) return;
    this.lastDirection.set(direction);

    this.http
      .post<SwipeResponse>(`${this.apiUrl}/swipes`, { targetId: profile.id, direction })
      .subscribe({
        next: (res) => {
          if (res?.match) {
            this.toast.push('match', "It's a match!", `You and ${profile.name} liked each other.`);
          }
        },
        error: () => {},
      });

    setTimeout(() => {
      this.index.update((i) => i + 1);
      this.lastDirection.set(null);
    }, 180);
  }

  viewProfile(id: string): void {
    this.router.navigate(['/users', id]);
  }

  reset(): void {
    this.load();
  }
}
